@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the editor area. You have the <strong>Editor</strong> role.</p>

